import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useRef,
  useState,
} from 'react';
import { createPortal } from 'react-dom';
import type { Placement } from '@o9ds/core';
import O9Button from '../Button/Button';
import O9IconButton from '../IconButton/IconButton';
import { useOverlay } from '../../hooks/useOverlay';
import { useFocusTrap } from '../../hooks/useFocusTrap';
import { usePositioning } from '../../hooks/usePositioning';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface O9PopoverAction {
  id?: string;
  label?: string;
  icon?: string;
  variant?: 'primary' | 'secondary' | 'tertiary' | 'danger';
  action?: (event: React.MouseEvent) => boolean | void;
  /** Alias for {@link action}. */
  onClick?: (event: React.MouseEvent) => boolean | void;
  isDisabled?: boolean;
}

export interface O9PopoverHeaderAction {
  id: string;
  type: 'btn' | 'dropdown' | 'switch';
  icon?: string;
  label?: string;
  onClick?: () => void;
  isChecked?: boolean;
  onChange?: (isChecked: boolean) => void;
  isDisabled?: boolean;
}

export interface O9PopoverProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'content' | 'title'> {
  variant?: 'space' | 'edge';
  placement?: 'top' | 'top-start' | 'top-end' | 'bottom' | 'bottom-start' | 'bottom-end'
    | 'left' | 'left-start' | 'left-end' | 'right' | 'right-start' | 'right-end' | 'auto';
  title?: string;
  hasHeader?: boolean;
  isClosable?: boolean;
  hasBackButton?: boolean;
  headerActions?: O9PopoverHeaderAction[];
  stickyHeader?: React.ReactNode;
  children?: React.ReactNode;
  actions?: O9PopoverAction[];
  hasFooter?: boolean;
  width?: string | number | 'anchor' | null;
  offset?: number;
  trigger?: 'click' | 'hover' | 'focus';
  closeOnOutside?: boolean;
  hasArrow?: boolean;
  isLoading?: boolean;
  isInteractive?: boolean;
  isOpen?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (isOpen: boolean) => void;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onBack?: () => void;
  triggerRef?: React.RefObject<HTMLElement | null>;
  renderTrigger?: (props: {
    ref: React.RefObject<HTMLElement | null>;
    'aria-expanded': boolean;
    'aria-controls': string;
    'aria-haspopup': 'dialog';
  }) => React.ReactNode;
  isInline?: boolean;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function mapPlacement(p: O9PopoverProps['placement']): Placement {
  switch (p) {
    case 'top': return 'top-start';
    case 'bottom': return 'bottom-start';
    case 'left': return 'left-start';
    case 'right': return 'right-start';
    default: return p as Placement;
  }
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9Popover = forwardRef<HTMLDivElement, O9PopoverProps>(
  function O9Popover(
    {
      variant = 'space',
      placement = 'auto',
      title,
      hasHeader = true,
      isClosable = true,
      hasBackButton = false,
      headerActions,
      stickyHeader,
      children,
      actions,
      hasFooter = true,
      width = null,
      offset = 2,
      trigger = 'click',
      closeOnOutside = true,
      hasArrow = false,
      isLoading = false,
      isInteractive = true,
      isOpen: openProp,
      defaultOpen = false,
      onOpenChange,
      onOpen,
      onClose,
      onBack,
      triggerRef: triggerRefProp,
      renderTrigger,
      isInline = false,
      className,
      ...rest
    },
    ref,
  ) {
    const uid = useId();
    const panelId = `o9ds-popover-${uid}`;
    const titleId = `o9ds-popover-title-${uid}`;

    const panelRef = useRef<HTMLDivElement>(null);
    const internalTriggerRef = useRef<HTMLElement | null>(null);
    const triggerRef = triggerRefProp ?? internalTriggerRef;

    useImperativeHandle(ref, () => panelRef.current!, []);

    // ── Controlled / Uncontrolled state ──────────────────────────────────
    const isControlled = openProp !== undefined;
    const [internalOpen, setInternalOpen] = useState(defaultOpen);
    const isOpen = isControlled ? openProp! : internalOpen;

    const setOpen = useCallback(
      (next: boolean) => {
        if (!isControlled) setInternalOpen(next);
        onOpenChange?.(next);
      },
      [isControlled, onOpenChange],
    );

    // ── Overlay hub ──────────────────────────────────────────────────────
    const overlay = useOverlay();

    // ── Hover delay refs ─────────────────────────────────────────────────
    const hoverOpenTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    const hoverCloseTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

    const clearHoverTimers = useCallback(() => {
      if (hoverOpenTimer.current) { clearTimeout(hoverOpenTimer.current); hoverOpenTimer.current = null; }
      if (hoverCloseTimer.current) { clearTimeout(hoverCloseTimer.current); hoverCloseTimer.current = null; }
    }, []);

    // ── Open / Close handlers ────────────────────────────────────────────
    const handleOpen = useCallback(() => {
      if (isOpen) return;
      if (onOpen?.() === false) return;

      setOpen(true);

      if (panelRef.current) {
        overlay.open({
          id: panelId,
          type: 'popover',
          element: panelRef.current,
          triggerElement: triggerRef.current ?? undefined,
          priority: 10,
          config: { autoCloseOnOutsideClick: closeOnOutside },
        });
      }

      triggerRef.current?.dispatchEvent(
        new CustomEvent('popover:open', { bubbles: true }),
      );
    }, [isOpen, onOpen, setOpen, overlay, panelId, triggerRef, closeOnOutside]);

    const handleClose = useCallback(() => {
      if (!isOpen) return;
      if (onClose?.() === false) return;

      setOpen(false);
      clearHoverTimers();
      overlay.close(panelId);
      triggerRef.current?.focus({ preventScroll: true });
      triggerRef.current?.dispatchEvent(
        new CustomEvent('popover:close', { bubbles: true }),
      );
    }, [isOpen, onClose, setOpen, clearHoverTimers, overlay, panelId, triggerRef]);

    const toggleOpen = useCallback(() => {
      if (isOpen) handleClose();
      else handleOpen();
    }, [isOpen, handleOpen, handleClose]);

    // ── Register panel with overlay hub when it opens ────────────────────
    useEffect(() => {
      if (!isOpen || !panelRef.current) return;
      overlay.open({
        id: panelId,
        type: 'popover',
        element: panelRef.current,
        triggerElement: triggerRef.current ?? undefined,
        priority: 10,
        config: { autoCloseOnOutsideClick: closeOnOutside },
        onClose: handleClose,
      });
      return () => { overlay.close(panelId); };
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen]);

    // ── Positioning ──────────────────────────────────────────────────────
    const mappedPlacement = mapPlacement(placement);
    const { position } = usePositioning({
      anchorRef: triggerRef,
      floatRef: panelRef,
      placement: mappedPlacement,
      gap: offset,
      enabled: isOpen && !isInline,
      width: width === 'anchor' ? 'anchor' : undefined,
    });

    // ── Focus trap ───────────────────────────────────────────────────────
    // Defer activation until positioning is resolved so that focus() does
    // not target an element sitting at (0, 0) which scrolls the viewport.
    const positioned = !!position || isInline;
    useFocusTrap(panelRef, {
      active: isInteractive && isOpen && positioned,
      escapeDeactivates: false,
      returnFocusOnDeactivate: true,
      allowOutsideClick: true,
    });

    // ── Escape key ───────────────────────────────────────────────────────
    useEffect(() => {
      if (!isOpen) return;
      const onKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') {
          e.stopPropagation();
          handleClose();
        }
      };
      document.addEventListener('keydown', onKeyDown, true);
      return () => document.removeEventListener('keydown', onKeyDown, true);
    }, [isOpen, handleClose]);

    // ── Outside click ────────────────────────────────────────────────────
    useEffect(() => {
      if (!isOpen || !closeOnOutside) return;
      const onPointerDown = (e: PointerEvent) => {
        const target = e.target as Node;
        if (panelRef.current?.contains(target)) return;
        if (triggerRef.current?.contains(target)) return;
        handleClose();
      };
      document.addEventListener('pointerdown', onPointerDown, true);
      return () => document.removeEventListener('pointerdown', onPointerDown, true);
    }, [isOpen, closeOnOutside, handleClose, triggerRef]);

    // ── Trigger ARIA attributes (when using triggerRef, not renderTrigger) ─
    useEffect(() => {
      const el = triggerRef.current;
      if (!el || renderTrigger) return;

      el.setAttribute('aria-haspopup', 'dialog');
      el.setAttribute('aria-controls', panelId);
      el.setAttribute('aria-expanded', String(isOpen));

      return () => {
        el.removeAttribute('aria-haspopup');
        el.removeAttribute('aria-controls');
        el.removeAttribute('aria-expanded');
      };
    }, [isOpen, panelId, triggerRef, renderTrigger]);

    // ── Trigger event listeners ──────────────────────────────────────────
    useEffect(() => {
      const el = triggerRef.current;
      if (!el) return;

      if (trigger === 'click') {
        const onClick = () => toggleOpen();
        el.addEventListener('click', onClick);
        return () => el.removeEventListener('click', onClick);
      }

      if (trigger === 'hover') {
        const onEnter = () => {
          clearHoverTimers();
          hoverOpenTimer.current = setTimeout(handleOpen, 150);
        };
        const onLeave = () => {
          clearHoverTimers();
          hoverCloseTimer.current = setTimeout(handleClose, 100);
        };
        el.addEventListener('pointerenter', onEnter);
        el.addEventListener('pointerleave', onLeave);
        return () => {
          el.removeEventListener('pointerenter', onEnter);
          el.removeEventListener('pointerleave', onLeave);
          clearHoverTimers();
        };
      }

      if (trigger === 'focus') {
        const onFocus = () => handleOpen();
        const onBlur = () => {
          setTimeout(() => {
            if (
              panelRef.current &&
              !panelRef.current.contains(document.activeElement)
            ) {
              handleClose();
            }
          }, 0);
        };
        el.addEventListener('focus', onFocus);
        el.addEventListener('blur', onBlur);
        return () => {
          el.removeEventListener('focus', onFocus);
          el.removeEventListener('blur', onBlur);
        };
      }
    }, [trigger, triggerRef, toggleOpen, handleOpen, handleClose, clearHoverTimers]);

    // ── Hover bridge (panel enter/leave) ─────────────────────────────────
    const handlePanelPointerEnter = useCallback(() => {
      if (trigger !== 'hover') return;
      clearHoverTimers();
    }, [trigger, clearHoverTimers]);

    const handlePanelPointerLeave = useCallback(() => {
      if (trigger !== 'hover') return;
      hoverCloseTimer.current = setTimeout(handleClose, 100);
    }, [trigger, handleClose]);

    // ── Action click ─────────────────────────────────────────────────────
    const handleActionClick = useCallback(
      (action: O9PopoverAction, e: React.MouseEvent) => {
        const callback = action.action ?? action.onClick;
        const result = callback?.(e);
        if (result !== false) handleClose();
      },
      [handleClose],
    );

    // ── Header action rendering ──────────────────────────────────────────
    const renderHeaderAction = (ha: O9PopoverHeaderAction) => {
      if (ha.type === 'btn') {
        return (
          <O9IconButton
            key={ha.id}
            icon={ha.icon!}
            variant="tertiary"
            size="sm"
            tooltip={ha.label!}
            onClick={ha.onClick}
            isDisabled={isLoading || ha.isDisabled}
          />
        );
      }
      // TODO: O9Switch in header context — not yet implemented
      if (ha.type === 'switch') {
        return <span key={ha.id} data-placeholder="switch" />;
      }
      // TODO: O9DropdownIconButton — not yet available
      return <span key={ha.id} data-placeholder="dropdown" />;
    };

    // ── Classes ──────────────────────────────────────────────────────────
    const panelClasses = [
      'o9ds-popover',
      variant === 'edge' && 'o9ds-popover--edge',
      hasArrow && 'o9ds-popover--with-arrow',
      actions && actions.length > 0 && hasFooter && 'o9ds-popover--with-footer',
      isClosable && 'o9ds-popover--closable',
      isInline && 'o9ds-popover--inline',
      isOpen && 'open',
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Style ────────────────────────────────────────────────────────────
    const panelStyle: React.CSSProperties = {
      ...(position
        ? { transform: `translate(${position.x}px, ${position.y}px)` }
        : {}),
      ...(position?.maxHeight != null
        ? { maxHeight: `${position.maxHeight}px` }
        : {}),
      ...(position?.width != null
        ? ({ '--o9ds-popover-width': position.width } as React.CSSProperties)
        : {}),
      ...(typeof width === 'number'
        ? ({ '--o9ds-popover-width': `${width}px` } as React.CSSProperties)
        : {}),
      ...(typeof width === 'string' && width !== 'anchor'
        ? ({ '--o9ds-popover-width': width } as React.CSSProperties)
        : {}),
      ...(!positioned ? { opacity: 0, pointerEvents: 'none' as const } : {}),
    };

    // ── Header section ───────────────────────────────────────────────────
    const renderHeader = () => {
      if (!hasHeader || !(isClosable || title || hasBackButton)) return null;
      return (
        <div className="o9ds-popover__header">
          <div className="o9ds-popover__header-left">
            {hasBackButton && (
              <span className="o9ds-popover__back-btn">
                <O9IconButton
                  icon="arrow-left"
                  variant="tertiary"
                  size="sm"
                  tooltip="Back"
                  aria-label="Back"
                  onClick={onBack}
                  isDisabled={isLoading}
                />
              </span>
            )}
            {title && (
              <span id={titleId} className="o9ds-popover__title">
                {title}
              </span>
            )}
          </div>
          <div className="o9ds-popover__header-actions">
            {headerActions?.map((ha) => renderHeaderAction(ha))}
            {isClosable && (
              <span className="o9ds-popover__close-btn">
                <O9IconButton
                  icon="close"
                  variant="tertiary"
                  size="sm"
                  tooltip="Close"
                  aria-label="Close"
                  onClick={handleClose}
                  isDisabled={isLoading}
                />
              </span>
            )}
          </div>
        </div>
      );
    };

    // ── Footer section ───────────────────────────────────────────────────
    const renderFooter = () => {
      if (!hasFooter || !actions || actions.length === 0) return null;
      return (
        <div className="o9ds-popover__footer">
          {actions.map((action) => {
            if (action.icon && !action.label) {
              return (
                <O9IconButton
                  key={action.id}
                  icon={action.icon}
                  variant={(action.variant ?? 'tertiary') as 'tertiary'}
                  size="md"
                  tooltip={action.label ?? action.id ?? ''}
                  onClick={(e) => handleActionClick(action, e)}
                  isDisabled={isLoading || action.isDisabled}
                />
              );
            }
            return (
              <O9Button
                key={action.id}
                label={action.label!}
                icon={action.icon}
                variant={action.variant ?? 'secondary'}
                size="md"
                onClick={(e) => handleActionClick(action, e)}
                isDisabled={isLoading || action.isDisabled}
              />
            );
          })}
        </div>
      );
    };

    // ── Render trigger (if renderTrigger provided) ───────────────────────
    const triggerContent = renderTrigger
      ? renderTrigger({
          ref: internalTriggerRef,
          'aria-expanded': isOpen,
          'aria-controls': panelId,
          'aria-haspopup': 'dialog',
        })
      : null;

    // ── Panel ────────────────────────────────────────────────────────────
    const panel = isOpen
      ? createPortal(
          <div
            ref={panelRef}
            id={panelId}
            className={panelClasses}
            role={isInteractive ? 'dialog' : 'tooltip'}
            aria-busy={isLoading || undefined}
            aria-labelledby={title ? titleId : undefined}
            tabIndex={isInteractive ? -1 : undefined}
            style={
              Object.keys(panelStyle).length > 0 ? panelStyle : undefined
            }
            onPointerEnter={handlePanelPointerEnter}
            onPointerLeave={handlePanelPointerLeave}
            {...rest}
          >
            {hasArrow && (
              <div className="o9ds-popover__arrow" aria-hidden="true" />
            )}
            {renderHeader()}
            {stickyHeader && (
              <div className="o9ds-popover__sticky-header">
                {stickyHeader}
              </div>
            )}
            <div className="o9ds-popover__body">{children}</div>
            {renderFooter()}
          </div>,
          document.body,
        )
      : null;

    return (
      <>
        {triggerContent}
        {panel}
      </>
    );
  },
);

export { O9Popover };
export default O9Popover;
